const week = Math.ceil(new Date().getDate() / 7);
const emails = [
  { subject: 'Fall cleanup season is here — book TotalGuard!', body: 'Hi {name},

Leaves are starting to fall in Madison! TotalGuard's fall cleanup includes leaf removal, yard cleanup, and bed prep for winter.

Book your fall cleanup at tgyardcare.com' },
  { subject: 'Your lawn needs aeration before winter', body: 'Hi {name},

Fall aeration is the single best thing you can do for your lawn before winter. Core aeration reduces compaction and helps roots grow stronger.

Book aeration at tgyardcare.com or call (608) 535-6057' },
  { subject: "Don't forget your gutters this fall!", body: 'Hi {name},

Leaf-clogged gutters can cause serious damage over winter. TotalGuard gutter cleaning removes all debris and flushes downspouts.

Book gutter cleaning at tgyardcare.com' },
  { subject: 'Winterize now — your lawn will thank you in spring', body: 'Hi {name},

Our complete fall package: cleanup + aeration + final fertilization + gutter cleaning. Everything your property needs before the first frost.

tgyardcare.com' }
];
const emailIdx = Math.min(week - 1, emails.length - 1);
const template = emails[emailIdx];
return $input.all().map(i => ({ json: { ...i.json, subject: template.subject, body: template.body.replace('{name}', i.json.first_name || 'there') } }));
